const MongoClient = require('mongodb').MongoClient;

function queryBuilder(filter, projection, sort) {
    const dbUrl = 'mongodb://localhost:27017'; // MongoDB connection URL
    const dbName = 'mydatabase'; // Database name

    const client = new MongoClient(dbUrl);
    client.connect((err, client) => {
        if (err) console.error(err);
        else {
            const db = client.db(dbName);

            const collection = db.collection('users'); // Collection to query

            let query = filter;
            let options = {};

            if ('projection' in projection && projection['projection']) {
                options.projection = projection['projection'];
                delete projection['projection'];
            }

            if (sort) {
                options.sort = sort;
            }

            collection.find(query, options).toArray((err, result) => {
                if (err) console.error(err);
                else {
                    client.close();
                    return result; // Return query results
                }
            });
        }
    });

    return function (req, res) { // Return a function that returns the query results
        const filter = req.body.filter;
        const projection = req.body.projection;
        const sort = req.body.sort;

        queryBuilder(filter, projection, sort).then(result => {
            res.json(result);
        }).catch(err => {
            res.status(500).json({ message: 'Error querying database' });
        });
    };
}

